  ('pukao-e3452428-moex-00146', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，臺北市與新北市對於跨區域公車路線規劃，涉及跨區域地方自治事項之辦理。 下列何者非屬法定可能之辦理方式？', '["由臺北市與新北市協商辦理", "由共同上級業務主管機關協調臺北市與新北市共同辦理", "由共同上級業務主管機關指定新北市限期辦理", "由共同上級業務主管機關直接統籌指揮辦理之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00147', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關跨域治理概念的敘述，下列何者錯誤？', '["跨域治理可以包含不同政策領域，乃至於公私部門之間的交互關係", "跨域治理概念的核心理念之一，是要引入市場機制，讓地方自治團體彼此有所競爭", "近年來因為政策資源日益稀少，非進行跨域整合不足以發揮以小搏大的綜合效用", "全球化之下，國家競爭日趨激烈，非進行跨域治理與府際合作，無法提升政府效率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00148', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '下列何者具有地方自治團體之公法人地位？', '["臺灣省", "臺北市松山區", "高雄市那瑪夏區", "臺南市北區大和里"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00149', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，中央與直轄市、縣（市）間，權限遇有爭議時，下列何者有調處之權？', '["總統", "立法院", "行政院", "內政部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00150', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關公共造產之敘述，下列何者正確？', '["公共造產限於由縣（市）政府、鄉（鎮、市）公所自行經營", "公共造產得由縣（市）政府、鄉（鎮、市）公所委託經營或合作開發經營", "公共造產經營方式，經各該立法機關議決後，縣（市）政府應報內政部核准", "縣（市）政府、鄉（鎮、市）公所為辦理公共造產，應儘先利用私有土地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00151', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依財政收支劃分法第 38 條規定，各級政府事務委託他級或同級政府辦理者，其經費由下列何者 負擔？', '["由中央政府負擔", "由被委託機關負擔", "由委託機關負擔", "由委託機關與被委託機關依比例負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00152', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '中華民國國民，除憲法另有規定外，年滿幾歲，未受監護宣告者，即有公民投票權？', '["16歲", "18歲", "20歲", "22歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
